import React from 'react';

function BingoBoard({ calledNumbers }) {
  // Generate numbers for each column
  const bingoNumbers = {
    B: Array.from({ length: 15 }, (_, i) => i + 1),
    I: Array.from({ length: 15 }, (_, i) => i + 16),
    N: Array.from({ length: 15 }, (_, i) => i + 31),
    G: Array.from({ length: 15 }, (_, i) => i + 46),
    O: Array.from({ length: 15 }, (_, i) => i + 61)
  };

  const isNumberCalled = (number) => {
    return calledNumbers.includes(number);
  };

  // Inline styles to match working cartela pattern
  const boardStyle = {
    background: 'rgba(0, 0, 0, 0.3)',
    borderRadius: '15px',
    padding: '15px',
    marginBottom: '20px'
  };

  const headerStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(5, 1fr)',
    gap: '8px',
    marginBottom: '10px',
    textAlign: 'center'
  };

  const headerCellStyle = {
    fontSize: '1.5rem',
    fontWeight: 'bold',
    color: '#ffd700',
    padding: '10px'
  };

  const rowStyle = {
    display: 'grid',
    gridTemplateColumns: 'repeat(5, 1fr)',
    gap: '8px',
    marginBottom: '8px'
  };

  const cellStyle = (called) => ({
    aspectRatio: '1',
    background: called 
      ? 'linear-gradient(135deg, #ffd700, #ffb347)' 
      : 'rgba(255, 255, 255, 0.1)',
    borderRadius: '8px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontWeight: 'bold',
    fontSize: '0.9rem',
    color: called ? '#1a1a2e' : '#fff',
    cursor: 'pointer',
    transition: 'all 0.2s',
    border: '1px solid rgba(255, 255, 255, 0.2)'
  });

  const statsStyle = {
    marginTop: '15px',
    display: 'flex',
    justifyContent: 'space-between',
    padding: '10px',
    background: 'rgba(0, 0, 0, 0.3)',
    borderRadius: '8px'
  };

  return (
    <div style={boardStyle}>
      <h3 style={{ textAlign: 'center', marginBottom: '15px', color: '#ffd700' }}>
        🎯 BINGO Number Board
      </h3>
      
      {/* Headers */}
      <div style={headerStyle}>
        <div style={headerCellStyle}>B</div>
        <div style={headerCellStyle}>I</div>
        <div style={headerCellStyle}>N</div>
        <div style={headerCellStyle}>G</div>
        <div style={headerCellStyle}>O</div>
      </div>
      
      {/* 15 Rows */}
      {[...Array(15)].map((_, rowIndex) => (
        <div key={rowIndex} style={rowStyle}>
          <div style={cellStyle(isNumberCalled(bingoNumbers.B[rowIndex]))}>
            {bingoNumbers.B[rowIndex]}
          </div>
          <div style={cellStyle(isNumberCalled(bingoNumbers.I[rowIndex]))}>
            {bingoNumbers.I[rowIndex]}
          </div>
          <div style={cellStyle(isNumberCalled(bingoNumbers.N[rowIndex]))}>
            {bingoNumbers.N[rowIndex]}
          </div>
          <div style={cellStyle(isNumberCalled(bingoNumbers.G[rowIndex]))}>
            {bingoNumbers.G[rowIndex]}
          </div>
          <div style={cellStyle(isNumberCalled(bingoNumbers.O[rowIndex]))}>
            {bingoNumbers.O[rowIndex]}
          </div>
        </div>
      ))}
      
      {/* Stats */}
      <div style={statsStyle}>
        <span>📊 Called: {calledNumbers.length}/75</span>
        <span style={{ color: '#ffd700' }}>
          {calledNumbers.length === 0 && 'Waiting for numbers...'}
          {calledNumbers.length > 0 && calledNumbers.length < 75 && 
            `${Math.round((calledNumbers.length / 75) * 100)}% Complete`}
          {calledNumbers.length === 75 && 'COMPLETE!'}
        </span>
      </div>
    </div>
  );
}

export default BingoBoard;
